     1→import React, { Suspense, useEffect, useState, useMemo } from 'react';
     2→import { indexedDBService } from '../services/indexedDB';
     3→import { useWidgetStore } from '../stores/useWidgetStore';
     4→import { WidgetManager } from '../components/WidgetManager';
     5→import { PresetManager } from '../components/PresetManager';
     6→import { BackgroundCustomizer, type BackgroundSettings } from '../components/BackgroundCustomizer';
     7→import { SortableWidget } from '../components/SortableWidget';
     8→import { WidgetErrorBoundary } from '../components/WidgetErrorBoundary';
     9→import { PageHeader } from '../components/PageHeader';
    10→// Masonry removed - using CSS Grid for proper column spanning support
    11→import { DndContext, closestCenter, PointerSensor, useSensor, useSensors, DragOverlay } from '@dnd-kit/core';
    12→import type { DragEndEvent, DragStartEvent } from '@dnd-kit/core';
    13→import { SortableContext, verticalListSortingStrategy } from '@dnd-kit/sortable';
    14→// Centralized widget registry - single source of truth for all widgets
    15→import { getWidgetComponentMap } from '../widgets/Dashboard/WidgetRegistry';
    16→import { logger } from '../services/logger';
    17→import { getContentContrastClass } from '../utils/colorUtils';
    18→
    19→const log = logger.module('Dashboard');
    20→
    21→// Loading fallback - improved skeleton with structure
    22→const WidgetLoader = () => (
    23→  <div className="h-64 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button overflow-hidden">
    24→    {/* Header skeleton */}
    25→    <div className="px-4 py-3 border-b border-border-light dark:border-border-dark flex items-center justify-between">
    26→      <div className="flex-1">
    27→        <div className="h-4 w-24 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    28→        <div className="h-3 w-16 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse mt-1" />
    29→      </div>
    30→      <div className="flex gap-1">
    31→        <div className="w-6 h-6 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    32→        <div className="w-6 h-6 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    33→      </div>
    34→    </div>
    35→    {/* Content skeleton */}
    36→    <div className="p-4 space-y-3">
    37→      <div className="h-4 w-full bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    38→      <div className="h-4 w-3/4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    39→      <div className="h-4 w-1/2 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    40→    </div>
    41→  </div>
    42→);
    43→
    44→// Widget components are now loaded from the centralized WidgetRegistry
    45→// See: src/widgets/Dashboard/WidgetRegistry.ts
    46→
    47→/**
    48→ * Dashboard Page - Personal overview
    49→ */
    50→export const Dashboard: React.FC = () => {
    51→  const [hasData, setHasData] = useState(true);
    52→  const [showBackupReminder, setShowBackupReminder] = useState(false);
    53→  const [showWidgetManager, setShowWidgetManager] = useState(false);
    54→  const [showPresetManager, setShowPresetManager] = useState(false);
    55→  const [showBackgroundCustomizer, setShowBackgroundCustomizer] = useState(false);
    56→  const [activeId, setActiveId] = useState<string | null>(null);
    57→
    58→  // Background settings (persisted to localStorage)
    59→  const [bgSettings, setBgSettings] = useState<BackgroundSettings>(() => {
    60→    const saved = localStorage.getItem('dashboard-background');
    61→    return saved
    62→      ? JSON.parse(saved)
    63→      : { type: 'none', value: '', opacity: 100, blur: 0 };
    64→  });
    65→  const enabledWidgets = useWidgetStore((state) => state.enabledWidgets);
    66→  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
    67→  const reorderWidgets = useWidgetStore((state) => state.reorderWidgets);
    68→
    69→  // Get widget components from centralized registry (memoized to prevent re-creation)
    70→  const WIDGET_COMPONENTS = useMemo(() => getWidgetComponentMap(), []);
    71→
    72→  // Calculate content contrast class based on background luminance
    73→  // This forces appropriate text colors when background contrasts with current theme
    74→  const contentContrastClass = useMemo(() => {
    75→    if (bgSettings.type === 'none' || !bgSettings.value) {
    76→      return '';
    77→    }
    78→    return getContentContrastClass(bgSettings.value) || '';
    79→  }, [bgSettings.type, bgSettings.value]);
    80→
    81→  // Configure drag sensors (require 5px movement to prevent accidental drags)
    82→  const sensors = useSensors(
    83→    useSensor(PointerSensor, {
    84→      activationConstraint: {
    85→        distance: 5,
    86→      },
    87→    })
    88→  );
    89→
    90→  // Handle drag start - track active widget for ghost preview
    91→  const handleDragStart = (event: DragStartEvent) => {
    92→    setActiveId(event.active.id as string);
    93→  };
    94→
    95→  // Handle drag end - reorder widgets
    96→  const handleDragEnd = (event: DragEndEvent) => {
    97→    const { active, over } = event;
    98→
    99→    if (over && active.id !== over.id) {
   100→      const oldIndex = enabledWidgets.indexOf(active.id as string);
   101→      const newIndex = enabledWidgets.indexOf(over.id as string);
   102→
   103→      if (oldIndex !== -1 && newIndex !== -1) {
   104→        const newOrder = [...enabledWidgets];
   105→        const [movedItem] = newOrder.splice(oldIndex, 1);
   106→        newOrder.splice(newIndex, 0, movedItem);
   107→        reorderWidgets(newOrder);
   108→      }
   109→    }
   110→
   111→    setActiveId(null);
   112→  };
   113→
   114→  useEffect(() => {
   115→    document.title = 'Neuman Brain';
   116→
   117→    // Check for hash navigation (#customize-widgets)
   118→    if (window.location.hash === '#customize-widgets') {
   119→      setShowWidgetManager(true);
   120→      // Clear the hash
   121→      window.history.replaceState(null, '', window.location.pathname);
   122→    }
   123→
   124→    // Check if user has any data
   125→    const checkForData = async () => {
   126→      try {
   127→        const keys = await indexedDBService.getAllKeys();
   128→        const hasAnyData = keys.length > 0;
   129→        setHasData(hasAnyData);
   130→
   131→        // Show backup reminder if no data AND not dismissed
   132→        const dismissed = localStorage.getItem('dashboard-backup-reminder-dismissed');
   133→        if (!hasAnyData && !dismissed) {
   134→          setShowBackupReminder(true);
   135→        }
   136→      } catch (error) {
   137→        log.error('Failed to check for data', { error });
   138→      }
   139→    };
   140→
   141→    checkForData();
   142→  }, []);
   143→
   144→  const handleDismissReminder = () => {
   145→    setShowBackupReminder(false);
   146→    localStorage.setItem('dashboard-backup-reminder-dismissed', 'true');
   147→  };
   148→
   149→  const handleBackgroundChange = (newSettings: BackgroundSettings) => {
   150→    setBgSettings(newSettings);
   151→    localStorage.setItem('dashboard-background', JSON.stringify(newSettings));
   152→  };
   153→
   154→  return (
   155→    <div className={`dashboard-page relative isolate ${contentContrastClass}`}>
   156→      {/* Background Layer - z-0 so it appears behind content but visible */}
   157→      {bgSettings.type !== 'none' && (
   158→        <div
   159→          className="dashboard-background fixed inset-0 pointer-events-none z-0"
   160→          style={{
   161→            backgroundImage: bgSettings.value,
   162→            backgroundSize: bgSettings.type === 'image' ? 'cover' : undefined,
   163→            backgroundPosition: bgSettings.type === 'image' ? 'center' : undefined,
   164→            backgroundAttachment: 'fixed',
   165→            opacity: bgSettings.opacity / 100,
   166→            filter: `blur(${bgSettings.blur}px)`,
   167→          }}
   168→        />
   169→      )}
   170→
   171→      <div className="relative z-10">
   172→        <PageHeader title="Dashboard" subtitle="Your personal management overview">
   173→          <button
   174→            onClick={() => setShowBackgroundCustomizer(true)}
   175→            className="px-3 py-1.5 text-sm bg-neutral-200 dark:bg-neutral-700 hover:bg-neutral-300 dark:hover:bg-neutral-600 text-text-light-primary dark:text-text-dark-primary rounded-lg font-medium transition-colors"
   176→            title="Customize background"
   177→          >
   178→            🎨 Background
   179→          </button>
   180→          <button
   181→            onClick={() => setShowPresetManager(true)}
   182→            className="px-3 py-1.5 text-sm bg-neutral-200 dark:bg-neutral-700 hover:bg-neutral-300 dark:hover:bg-neutral-600 text-text-light-primary dark:text-text-dark-primary rounded-lg font-medium transition-colors"
   183→            title="Manage layout presets"
   184→          >
   185→            📐 Presets
   186→          </button>
   187→        </PageHeader>
   188→      </div>
   189→
   190→      {/* First-Time User Backup Reminder */}
   191→      {showBackupReminder && !hasData && (
   192→        <div className="mb-6 p-6 rounded-lg bg-yellow-50 dark:bg-yellow-900/20 border-2 border-yellow-400 dark:border-yellow-600">
   193→          <div className="flex items-start gap-4">
   194→            <span className="text-3xl">⚠️</span>
   195→            <div className="flex-1">
   196→              <h3 className="text-xl font-bold text-yellow-900 dark:text-yellow-300 mb-2">
   197→                Welcome to Neuman Brain!
   198→              </h3>
   199→              <p className="text-sm text-yellow-800 dark:text-yellow-400 mb-3">
   200→                <strong>Important:</strong> Your data is stored locally in this browser. To protect your work, remember to create regular backups!
   201→              </p>
   202→              <div className="bg-white dark:bg-surface-dark-elevated p-4 rounded-lg mb-4">
   203→                <p className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-2">
   204→                  Quick Start:
   205→                </p>
   206→                <ol className="text-sm text-text-light-secondary dark:text-text-dark-secondary space-y-1 list-decimal list-inside ml-2">
   207→                  <li>Start creating tasks, notes, and plans</li>
   208→                  <li>When you have data to protect, go to Settings → Backup</li>
   209→                  <li>Export your first backup (Chrome/Edge: enable Auto-Save!)</li>
   210→                  <li>Store your .brain file somewhere safe (cloud, USB, etc.)</li>
   211→                </ol>
   212→              </div>
   213→              <button
   214→                onClick={handleDismissReminder}
   215→                className="px-4 py-2 bg-yellow-600 hover:bg-yellow-700 text-white rounded-lg font-medium"
   216→              >
   217→                Got It!
   218→              </button>
   219→            </div>
   220→          </div>
   221→        </div>
   222→      )}
   223→
   224→      {/* Dashboard Grid Layout - CSS Grid with column spanning + drag-drop */}
