      {/* Create/Edit Event Modal */}
      {eventModalData && (
        <EventCreateModal
          dateKey={eventModalData.dateKey}
          event={eventModalData.event}
          onClose={() => setEventModalData(null)}
        />
      )}
    </div>
  );
}

